/**
 * Browser-compatible watermark removal engine.
 * Adapted from gemini-watermark-remover (https://github.com/GargantuaX/gemini-watermark-remover)
 *
 * Removes the Gemini/nanobanana watermark using reverse alpha blending:
 *   original = (watermarked - α × 255) / (1 - α)
 */

const ASSETS = {
  bg48: 'data:image/png;base64,',
  bg96: 'data:image/png;base64,',
}

const CONSTANTS = {
  ALPHA_THRESHOLD: 0.002,
  MAX_ALPHA: 0.99,
  LOGO_VALUE: 255,
}

function loadImage(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => resolve(img)
    img.onerror = reject
    img.src = src
  })
}

function calculateAlphaMap(image: HTMLImageElement): Float32Array {
  const canvas = document.createElement('canvas')
  canvas.width = image.width
  canvas.height = image.height
  const ctx = canvas.getContext('2d', { willReadFrequently: true })!
  ctx.drawImage(image, 0, 0)

  const { data } = ctx.getImageData(0, 0, image.width, image.height)
  const alphaMap = new Float32Array(image.width * image.height)

  for (let i = 0; i < alphaMap.length; i++) {
    const idx = i * 4
    const maxChannel = Math.max(data[idx], data[idx + 1], data[idx + 2])
    alphaMap[i] = maxChannel / 255
  }
  return alphaMap
}

const alphaMaps: Record<number, Float32Array> = {}
let bgImages: { bg48: HTMLImageElement; bg96: HTMLImageElement } | null = null

async function getAlphaMap(size: number): Promise<Float32Array> {
  if (alphaMaps[size]) {
    return alphaMaps[size]
  }

  if (!bgImages) {
    const [bg48, bg96] = await Promise.all([
      loadImage(ASSETS.bg48),
      loadImage(ASSETS.bg96),
    ])
    bgImages = { bg48, bg96 }
  }

  const bgImage = size === 48 ? bgImages.bg48 : bgImages.bg96
  const alphaMap = calculateAlphaMap(bgImage)
  alphaMaps[size] = alphaMap
  return alphaMap
}

export async function removeWatermark(
  imgSource: HTMLImageElement
): Promise<Blob> {
  const canvas = document.createElement('canvas')
  canvas.width = imgSource.naturalWidth
  canvas.height = imgSource.naturalHeight
  const ctx = canvas.getContext('2d', { willReadFrequently: true })!
  ctx.drawImage(imgSource, 0, 0)

  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)

  const isLarge = canvas.width > 1024 && canvas.height > 1024
  const logoSize = isLarge ? 96 : 48
  const margin = isLarge ? 64 : 32

  const pos = {
    x: canvas.width - margin - logoSize,
    y: canvas.height - margin - logoSize,
  }

  const alphaMap = await getAlphaMap(logoSize)
  const { ALPHA_THRESHOLD, MAX_ALPHA, LOGO_VALUE } = CONSTANTS

  for (let row = 0; row < logoSize; row++) {
    for (let col = 0; col < logoSize; col++) {
      let alpha = alphaMap[row * logoSize + col]
      if (alpha < ALPHA_THRESHOLD) {
        continue
      }

      alpha = Math.min(alpha, MAX_ALPHA)
      const oneMinusAlpha = 1 - alpha
      const imgIdx = ((pos.y + row) * canvas.width + (pos.x + col)) * 4

      for (let c = 0; c < 3; c++) {
        const watermarked = imageData.data[imgIdx + c]
        const original = (watermarked - alpha * LOGO_VALUE) / oneMinusAlpha
        imageData.data[imgIdx + c] = Math.max(
          0,
          Math.min(255, Math.round(original))
        )
      }
    }
  }

  ctx.putImageData(imageData, 0, 0)

  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) {
        resolve(blob)
      } else {
        reject(new Error('Canvas to Blob failed'))
      }
    })
  })
}
